namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalStars { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount == 0 ? 0 : (double)TotalStars / RatingCount;
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new() { Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Ingredients = ["2 cups flour", "2 eggs", "1.5 cups milk", "2 tbsp sugar", "1 tsp baking powder"],
            Steps = ["Mix dry ingredients.", "Whisk eggs and milk together.", "Combine wet and dry.", "Cook on griddle until golden."] },
        new() { Id = 2, Title = "Avocado Toast", Category = "Breakfast",
            Ingredients = ["2 slices bread", "1 ripe avocado", "Salt and pepper", "Lemon juice"],
            Steps = ["Toast bread.", "Mash avocado with lemon juice, salt, and pepper.", "Spread on toast."] },
        new() { Id = 3, Title = "Grilled Chicken Salad", Category = "Lunch",
            Ingredients = ["2 chicken breasts", "Mixed greens", "Cherry tomatoes", "Olive oil", "Balsamic vinegar"],
            Steps = ["Season and grill chicken.", "Chop vegetables.", "Slice chicken and arrange on greens.", "Drizzle with dressing."] },
        new() { Id = 4, Title = "Tomato Basil Soup", Category = "Lunch",
            Ingredients = ["6 tomatoes", "1 onion", "3 cloves garlic", "Fresh basil", "Vegetable broth"],
            Steps = ["Sauté onion and garlic.", "Add chopped tomatoes and broth.", "Simmer 20 minutes.", "Blend until smooth, stir in basil."] },
        new() { Id = 5, Title = "Spaghetti Carbonara", Category = "Dinner",
            Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Parmesan", "Black pepper"],
            Steps = ["Cook pasta al dente.", "Fry pancetta until crisp.", "Whisk yolks with Parmesan.", "Toss hot pasta with pancetta, then egg mixture off heat."] },
        new() { Id = 6, Title = "Beef Stir Fry", Category = "Dinner",
            Ingredients = ["500g beef strips", "Bell peppers", "Soy sauce", "Garlic", "Ginger", "Rice"],
            Steps = ["Cook rice.", "Stir-fry beef on high heat.", "Add vegetables and aromatics.", "Add soy sauce, serve over rice."] },
        new() { Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts",
            Ingredients = ["2.25 cups flour", "1 cup butter", "0.75 cup sugar", "2 eggs", "2 cups chocolate chips"],
            Steps = ["Cream butter and sugar.", "Beat in eggs.", "Mix in flour.", "Fold in chocolate chips.", "Bake at 375°F for 10 minutes."] },
        new() { Id = 8, Title = "Tiramisu", Category = "Desserts",
            Ingredients = ["6 egg yolks", "Mascarpone", "Espresso", "Ladyfingers", "Cocoa powder"],
            Steps = ["Whisk yolks with sugar, fold in mascarpone.", "Dip ladyfingers in espresso.", "Layer cream and ladyfingers.", "Chill 4 hours, dust with cocoa."] },
    ];

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalStars += stars;
            recipe.RatingCount++;
        }
    }

    public void AddRecipe(string title, string category, List<string> ingredients, List<string> steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = "";

    private IReadOnlyList<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = Recipes.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService Recipes

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, that recipe doesn't exist.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>

    <div class="mb-4">
        <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" RatingCount="recipe.RatingCount" />
    </div>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = Recipes.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService Recipes

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.5rem; cursor: pointer; color: @(star <= hoveredStar ? "gold" : "#ccc");"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = 0"
              title="Rate @star stars">★</span>
    }
    <span class="ms-2 text-muted">
        @if (RatingCount > 0)
        {
            @($"{CurrentAverage:F1} ({RatingCount} ratings)")
        }
        else
        {
            @("Be the first to rate!")
        }
    </span>
    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Rated!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int hoveredStar;
    private bool submitted;

    private void Rate(int stars)
    {
        Recipes.AddRating(RecipeId, stars);
        var recipe = Recipes.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService Recipes
@inject NavigationManager Nav

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Breakfast">Breakfast</option>
            <option value="Lunch">Lunch</option>
            <option value="Dinner">Dinner</option>
            <option value="Desserts">Desserts</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" @bind-Value="model.IngredientsText" class="form-control" rows="5"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        <ValidationMessage For="() => model.IngredientsText" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="model.StepsText" class="form-control" rows="5"
                       placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Bake for 30 minutes." />
        <ValidationMessage For="() => model.StepsText" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        var ingredients = model.IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        var steps = model.StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        Recipes.AddRecipe(model.Title, model.Category, ingredients, steps);
        successMessage = $""{model.Title}" has been submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string IngredientsText { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string StepsText { get; set; } = "";
    }
}

