{"path": "/tmp/sv-f8ff02e8a6e84c049c979f51f5133ae7/RecipeShare/Components/Pages/StarRating.razor", "file_text": "@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService Recipes

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.5rem; cursor: pointer; color: @(star <= hoveredStar ? "gold" : "#ccc");"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = 0"
              title="Rate @star stars">★</span>
    }
    <span class="ms-2 text-muted">
        @if (RatingCount > 0)
        {
            @($"{CurrentAverage:F1} ({RatingCount} ratings)")
        }
        else
        {
            @("Be the first to rate!")
        }
    </span>
    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Rated!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int hoveredStar;
    private bool submitted;

    private void Rate(int stars)
    {
        Recipes.AddRating(RecipeId, stars);
        var recipe = Recipes.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        submitted = true;
    }
}
"}

{"path": "/tmp/sv-f8ff02e8a6e84c049c979f51f5133ae7/RecipeShare/Components/Pages/SubmitRecipe.razor", "file_text": "@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService Recipes
@inject NavigationManager Nav

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            <option value="Breakfast">Breakfast</option>
            <option value="Lunch">Lunch</option>
            <option value="Dinner">Dinner</option>
            <option value="Desserts">Desserts</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" @bind-Value="model.IngredientsText" class="form-control" rows="5"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        <ValidationMessage For="() => model.IngredientsText" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" @bind-Value="model.StepsText" class="form-control" rows="5"
                       placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Bake for 30 minutes." />
        <ValidationMessage For="() => model.StepsText" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        var ingredients = model.IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        var steps = model.StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        Recipes.AddRecipe(model.Title, model.Category, ingredients, steps);
        successMessage = $""{model.Title}" has been submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string IngredientsText { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string StepsText { get; set; } = "";
    }
}
"}

